import { IMessageComposer } from '@nitrots/nitro-renderer';

export class HaircutSelectStyleComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(offerId: number, hrCode: string)
{
this._data = [ offerId, hrCode ];

console.log('Packet HaircutSelectStyleComposer sent', this._data);
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}